window.Renderer = {
  renderAll() {
    Renderer.renderInputs();
    Renderer.renderPlayers();
    Renderer.renderBody();
    Renderer.renderBoard();
    Renderer.renderTurnInfo();
    Renderer.renderLog();
  },

  renderInputs() {
    Utils.el("playerCountInput").value = STATE.players.length || 2;

    Utils.el("toolsInput").value = STATE.libraries.tools.join("\n");
    Utils.el("posturesInput").value = STATE.libraries.postures.join("\n");
    Utils.el("maxCountInput").value = STATE.maxCount || 3;

    Utils.el("rewardInput").value = STATE.libraries.reward.join("\n");
    Utils.el("trapInput").value = STATE.libraries.trap.join("\n");
    Utils.el("specialInput").value = STATE.libraries.special.join("\n");

    Utils.el("boardSizeInput").value = STATE.boardConfig.size;

    const columnsInput = Utils.el("boardColumnsInput");
    if (columnsInput) columnsInput.value = STATE.boardConfig.columns || 10;

    Utils.el("rewardWeightInput").value = STATE.boardConfig.weights.reward;
    Utils.el("punishWeightInput").value = STATE.boardConfig.weights.punish;
    Utils.el("specialWeightInput").value = STATE.boardConfig.weights.special;
    Utils.el("trapWeightInput").value = STATE.boardConfig.weights.trap;
  },

  renderPlayers() {
    const root = Utils.el("playersEditor");
    root.innerHTML = "";

    STATE.players.forEach((player, index) => {
      const div = document.createElement("div");
      div.className = "playerCard";
      div.innerHTML = `
        <div class="playerHeader">
          <strong>玩家 ${index + 1}</strong>
          <span>当前位置：${player.pos}</span>
        </div>
        <label>名字</label>
        <input value="${player.name}" data-player-name="${index}">
        <label>性别</label>
        <select data-player-gender="${index}">
          <option value="male" ${player.gender === "male" ? "selected" : ""}>男</option>
          <option value="female" ${player.gender === "female" ? "selected" : ""}>女</option>
        </select>
      `;
      root.appendChild(div);
    });

    root.querySelectorAll("[data-player-name]").forEach(input => {
      input.addEventListener("input", e => {
        Players.update(Number(e.target.dataset.playerName), {
          name: e.target.value || "玩家"
        });
      });
    });

    root.querySelectorAll("[data-player-gender]").forEach(select => {
      select.addEventListener("change", e => {
        Players.update(Number(e.target.dataset.playerGender), {
          gender: e.target.value
        });
      });
    });
  },

  renderBody() {
    const root = Utils.el("bodyEditor");
    root.innerHTML = "";

    STATE.bodyParts.forEach((part, index) => {
      const percent = Body.percent(part);
      const div = document.createElement("div");
      div.className = "bodyCard";
      div.innerHTML = `
        <div class="bodyHeader">
          <strong>${part.name}</strong>
          <span class="bodyMeta">${part.enabled ? percent + "%" : "已禁用"} ${part.femaleOnly ? "｜女性限定" : ""}</span>
        </div>

        <label>
          <input type="checkbox" ${part.enabled ? "checked" : ""} data-body-enabled="${index}">
          启用
        </label>

        <label>
          <input type="checkbox" ${part.femaleOnly ? "checked" : ""} data-body-female="${index}">
          女性限定
        </label>

        <div class="bodyControls">
          <div>
            <label>权重：${part.weight}</label>
            <input type="range" min="1" max="100" value="${part.weight}" data-body-weight="${index}">
            <div class="percentBar"><div class="percentFill" style="width:${percent}%"></div></div>
          </div>
          <div>
            <label>强度：${part.strength}</label>
            <input type="range" min="0.1" max="2" step="0.1" value="${part.strength}" data-body-strength="${index}">
          </div>
        </div>

        <button class="danger" data-body-remove="${index}">删除部位</button>
      `;
      root.appendChild(div);
    });

    root.querySelectorAll("[data-body-enabled]").forEach(input => {
      input.addEventListener("change", e => {
        Body.update(Number(e.target.dataset.bodyEnabled), {
          enabled: e.target.checked
        });
      });
    });

    root.querySelectorAll("[data-body-female]").forEach(input => {
      input.addEventListener("change", e => {
        Body.update(Number(e.target.dataset.bodyFemale), {
          femaleOnly: e.target.checked
        });
      });
    });

    root.querySelectorAll("[data-body-weight]").forEach(input => {
      input.addEventListener("input", e => {
        Body.update(Number(e.target.dataset.bodyWeight), {
          weight: Number(e.target.value)
        });
      });
    });

    root.querySelectorAll("[data-body-strength]").forEach(input => {
      input.addEventListener("input", e => {
        Body.update(Number(e.target.dataset.bodyStrength), {
          strength: Number(e.target.value)
        });
      });
    });

    root.querySelectorAll("[data-body-remove]").forEach(button => {
      button.addEventListener("click", e => {
        Body.remove(Number(e.target.dataset.bodyRemove));
      });
    });
  },

  pathPosition(index) {
    const cols = STATE.boardConfig.columns || 10;
    const gapX = 82;
    const gapY = 78;
    const padX = 20;
    const padY = 18;

    const row = Math.floor(index / cols);
    const colInRow = index % cols;

    // 蛇形：偶数行从左到右，奇数行从右到左。
    const col = row % 2 === 0 ? colInRow : cols - 1 - colInRow;

    return {
      x: padX + col * gapX,
      y: padY + row * gapY,
      row,
      col
    };
  },

  iconFor(cell) {
    if (cell.type === "start") return { html: "💗", label: "START", extraClass: "startIcon" };
    if (cell.type === "goal") return { html: "🏁", label: "GOAL", extraClass: "goalIcon" };

    if (cell.type === "reward") return { html: "🎁", label: "", extraClass: "rewardGiftIcon" };
    if (cell.type === "trap") {
      return {
        html: '<img class="customCellIcon customTrapIcon" src="data:image/png;base64," alt="陷阱">',
        label: "",
        extraClass: "customCellIconWrap"
      };
    }
    if (cell.type === "special") {
      return {
        html: '<img class="specialWingIcon" src="assets/special-wing.png" alt="特殊">',
        label: "",
        extraClass: "specialWingIconWrap"
      };
    }

    if (cell.type === "punish") {
      return {
        html: '<img class="customCellIcon customPunishIcon" src="data:image/png;base64," alt="惩罚">',
        label: "",
        extraClass: "customCellIconWrap"
      };
    }
    return { html: "", label: "", extraClass: "" };
  },

  renderPathLines() {
    const maxIndex = STATE.board.length - 1;
    if (maxIndex < 1) return "";

    let lines = "";

    for (let i = 0; i < maxIndex; i++) {
      const a = Renderer.pathPosition(i);
      const b = Renderer.pathPosition(i + 1);

      const x1 = a.x + 29;
      const y1 = a.y + 29;
      const x2 = b.x + 29;
      const y2 = b.y + 29;

      lines += `<line class="pathLine" x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" />`;
    }

    return `<svg class="pathLineSvg" width="100%" height="100%">${lines}</svg>`;
  },

  renderBoard() {
    const board = Utils.el("board");
    const cols = STATE.boardConfig.columns || 10;
    const rows = Math.ceil(Math.max(STATE.board.length, 1) / cols);

    board.style.width = (cols * 82 + 70) + "px";
    board.style.height = (rows * 78 + 80) + "px";

    board.innerHTML = Renderer.renderPathLines();

    STATE.board.forEach((cell, index) => {
      const pos = Renderer.pathPosition(index);
      const meta = Renderer.iconFor(cell);

      const div = document.createElement("div");
      div.className = "cell " + cell.type;
      div.dataset.index = index;
      div.style.left = pos.x + "px";
      div.style.top = pos.y + "px";

      const playersHere = STATE.players
        .filter(p => p.pos === index)
        .map(p => `<span class="playerToken">${p.name}</span>`)
        .join("");

      div.innerHTML = `
        ${playersHere ? `<div class="playerStack">${playersHere}</div>` : ""}
        <div class="cellIcon ${meta.extraClass || ""}">${meta.html}</div>
        ${meta.label ? `<div class="cellLabel">${meta.label}</div>` : ""}
        <div class="cellIndex">${index}</div>
      `;

      board.appendChild(div);
    });
  },

  cellCenter(index) {
    const cell = document.querySelector(`.cell[data-index="${index}"]`);
    if (!cell) return null;

    return {
      left: cell.offsetLeft + cell.offsetWidth / 2,
      top: cell.offsetTop + cell.offsetHeight / 2
    };
  },

  async shakeDiceCup(step) {
    Renderer.injectUiPatchStyles();

    const panel = Utils.el("eventPanel");
    if (!panel) return;

    let overlay = document.getElementById("diceCupOverlay");
    if (!overlay) {
      overlay = document.createElement("div");
      overlay.id = "diceCupOverlay";
      overlay.innerHTML = `
        <div class="diceCupStage">
          <div class="diceCup">
            <div class="diceCupLid"></div>
            <div class="diceCupBody">● ●</div>
          </div>
          <div class="diceResultFace" id="diceResultFace">?</div>
          <div class="diceCupText">骰盅摇晃中...</div>
        </div>
      `;
      panel.appendChild(overlay);
    }

    const result = overlay.querySelector("#diceResultFace");
    const text = overlay.querySelector(".diceCupText");
    if (result) result.textContent = "?";
    if (text) text.textContent = "骰盅摇晃中...";

    overlay.classList.add("show", "shaking");
    Renderer.playDiceCupSound();

    await (Utils.sleep ? Utils.sleep(920) : new Promise(resolve => setTimeout(resolve, 920)));

    overlay.classList.remove("shaking");
    if (result) result.textContent = step;
    if (text) text.textContent = `摇到 ${step} 点`;

    await (Utils.sleep ? Utils.sleep(560) : new Promise(resolve => setTimeout(resolve, 560)));
    overlay.classList.remove("show");
  },

  playDiceCupSound() {
    try {
      const AudioContext = window.AudioContext || window.webkitAudioContext;
      if (!AudioContext) return;

      const ctx = new AudioContext();
      const now = ctx.currentTime;

      for (let i = 0; i < 15; i++) {
        const t = now + i * 0.055;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = i % 2 ? "square" : "triangle";
        osc.frequency.setValueAtTime(150 + Math.random() * 520, t);
        gain.gain.setValueAtTime(0.0001, t);
        gain.gain.exponentialRampToValueAtTime(0.12, t + 0.008);
        gain.gain.exponentialRampToValueAtTime(0.0001, t + 0.052);
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start(t);
        osc.stop(t + 0.06);
      }

      setTimeout(() => ctx.close && ctx.close(), 1300);
    } catch (e) {
      // 浏览器禁止音频或不支持 WebAudio 时静默跳过。
    }
  },

  animateMove(player, from, to, options = {}) {
    return new Promise(resolve => {
      Renderer.renderBoard();

      const board = Utils.el("board");
      const start = Renderer.cellCenter(from);

      if (!start || from === to) {
        resolve();
        return;
      }

      const token = document.createElement("div");
      token.className = "movingToken movingTokenJump";
      token.textContent = player.name;
      board.appendChild(token);

      const setTokenPos = (center) => {
        token.style.left = (center.left - 20) + "px";
        token.style.top = (center.top - 17) + "px";
      };

      setTokenPos(start);

      const direction = to > from ? 1 : -1;
      const isBackToStart = to === 0 && options.instantToStart;
      const path = [];

      if (isBackToStart) {
        path.push(to);
      } else {
        for (let i = from + direction; direction > 0 ? i <= to : i >= to; i += direction) {
          path.push(i);
        }
      }

      let idx = 0;
      const jumpNext = () => {
        if (idx >= path.length) {
          token.remove();
          resolve();
          return;
        }

        const nextCenter = Renderer.cellCenter(path[idx]);
        idx++;

        if (!nextCenter) {
          jumpNext();
          return;
        }

        token.classList.remove("jumping");
        void token.offsetWidth;
        token.classList.add("jumping");
        setTokenPos(nextCenter);

        setTimeout(jumpNext, isBackToStart ? 280 : 230);
      };

      setTimeout(jumpNext, 40);
    });
  },

  injectUiPatchStyles() {
    if (document.getElementById("spFlyingChessUiPatchStyles")) return;

    const style = document.createElement("style");
    style.id = "spFlyingChessUiPatchStyles";
    style.textContent = `
      .rewardGiftIcon{font-size:32px;line-height:1;filter:drop-shadow(0 2px 0 rgba(255,255,255,.65));}
      .customCellIconWrap{display:grid;place-items:center;width:38px;height:38px;}
      .customCellIcon{max-width:36px;max-height:36px;object-fit:contain;display:block;mix-blend-mode:multiply;}
      .customTrapIcon{filter:drop-shadow(0 2px 0 rgba(255,255,255,.45));}
      .customPunishIcon{border-radius:6px;filter:contrast(1.08) drop-shadow(0 2px 0 rgba(255,255,255,.55));}
      .movingTokenJump{transition:left .18s ease,top .18s ease,transform .18s ease;}
      .movingTokenJump.jumping{animation:tokenStepJump .23s ease;}
      @keyframes tokenStepJump{0%{transform:translateY(0) scale(1)}45%{transform:translateY(-15px) scale(1.08)}100%{transform:translateY(0) scale(1)}}
      #diceCupOverlay{position:absolute;inset:0;display:none;align-items:center;justify-content:center;z-index:120;border-radius:20px;background:rgba(47,24,36,.68);backdrop-filter:blur(2px);}
      #diceCupOverlay.show{display:flex;}
      .diceCupStage{text-align:center;color:#fff;font-weight:900;}
      .diceCup{width:96px;height:104px;margin:0 auto 12px;position:relative;transform-origin:50% 20%;}
      #diceCupOverlay.shaking .diceCup{animation:diceCupShake .09s linear infinite;}
      .diceCupLid{width:88px;height:18px;margin:0 auto;border-radius:999px;background:linear-gradient(135deg,#fff,#ffd8e7);border:3px solid #7b2e52;box-shadow:0 5px 0 rgba(0,0,0,.18);}
      .diceCupBody{width:78px;height:78px;margin:-3px auto 0;border-radius:16px 16px 24px 24px;background:linear-gradient(135deg,#9b5de5,#d65a82);border:4px solid #fff;display:grid;place-items:center;font-size:20px;letter-spacing:4px;box-shadow:0 14px 26px rgba(0,0,0,.28);}
      .diceResultFace{width:54px;height:54px;margin:0 auto 8px;border-radius:14px;background:#fff;color:#7b2e52;display:grid;place-items:center;font-size:32px;border:3px solid #ff9ec0;box-shadow:0 8px 18px rgba(0,0,0,.22);}
      .diceCupText{font-size:20px;text-shadow:0 2px 8px rgba(0,0,0,.32);}
      @keyframes diceCupShake{0%{transform:translateX(-8px) rotate(-10deg)}50%{transform:translateX(8px) rotate(10deg)}100%{transform:translateX(-5px) rotate(-7deg)}}
    `;
    document.head.appendChild(style);
  },

  renderTurnInfo() {
    const info = Utils.el("turnInfo");

    if (!STATE.game.started) {
      info.textContent = STATE.board.length ? "棋盘已生成，等待开始" : "等待生成棋盘";
      return;
    }

    if (STATE.game.finished) {
      info.textContent = "游戏结束";
      return;
    }

    const current = Players.current();
    info.textContent = current ? `当前回合：${current.name}` : "无玩家";
  },

  showEvent(text) {
    Utils.el("eventContent").textContent = text;
  },

  addLog(text) {
    STATE.history.unshift({
      time: new Date().toLocaleTimeString(),
      text
    });
    Renderer.renderLog();
  },

  renderLog() {
    const root = Utils.el("logList");
    root.innerHTML = "";

    STATE.history.slice(0, 60).forEach(item => {
      const div = document.createElement("div");
      div.className = "logItem";
      div.textContent = `[${item.time}] ${item.text}`;
      root.appendChild(div);
    });
  },

  showWinnerModal(player) {
    let overlay = document.getElementById("winnerOverlay");

    if (!overlay) {
      overlay = document.createElement("div");
      overlay.id = "winnerOverlay";
      overlay.innerHTML = `
        <div class="winnerModal">
          <button class="winnerClose" id="winnerCloseBtn">×</button>
          <div class="winnerCrown">👑</div>
          <div class="winnerAvatar">
            <span class="winnerHeart">❤</span>
            <span id="winnerName"></span>
          </div>
          <div class="winnerTitle">胜者诞生</div>
          <div class="winnerPrize">
            奖品：至高无上的权利<br>
            玩家获得任意处置其余玩家的权利
          </div>
        </div>
      `;
      document.body.appendChild(overlay);

      overlay.addEventListener("click", (e) => {
        if (e.target.id === "winnerOverlay" || e.target.id === "winnerCloseBtn") {
          overlay.classList.remove("show");
        }
      });
    }

    const name = document.getElementById("winnerName");
    if (name) name.textContent = player.name;

    overlay.classList.add("show");
  }

};


// 单文件 UI 补丁：由于只允许替换 renderer.js，这里在 renderer.js 加载后覆盖 Game.roll，
// 以实现“点击掷骰子 -> 骰盅动画+碰撞音 -> 显示点数 -> 棋子逐格跳动”。
(function patchFlyingChessGameRoll() {
  Renderer.injectUiPatchStyles && Renderer.injectUiPatchStyles();

  if (!window.Game || Game.__rendererUiPatched) return;
  Game.__rendererUiPatched = true;

  Game.roll = async function rollWithDiceCup() {
    if (STATE.game.animating) return;

    if (!STATE.game.started) {
      Renderer.showEvent("请先开始游戏");
      return;
    }

    if (STATE.game.finished) {
      Renderer.showEvent("游戏已结束，请重新生成棋盘或重新开始。");
      return;
    }

    const player = Players.current();
    if (!player) return;

    if (player.skipTurn) {
      player.skipTurn = false;
      Renderer.showEvent(`${player.name}\n跳过本回合`);
      Renderer.addLog(`${player.name} 跳过本回合`);
      STATE.game.turn++;
      Renderer.renderTurnInfo();
      Storage.autoSave();
      return;
    }

    const step = Math.floor(Math.random() * 6) + 1;
    const from = player.pos;
    const to = Utils.clamp(player.pos + step, 0, STATE.board.length - 1);

    STATE.game.animating = true;
    await Renderer.shakeDiceCup(step);
    await Renderer.animateMove(player, from, to);
    player.pos = to;
    STATE.game.animating = false;

    let eventText = `${player.name}\n🎲 摇到 ${step} 点，前进 ${step} 格`;
    eventText += await Game.resolveCurrentCell(player, 0);

    if (player.pos >= STATE.board.length - 1) {
      STATE.game.finished = true;
      eventText += `\n\n🏁 ${player.name} 到达终点`;
      Renderer.showWinnerModal(player);
    }

    const hasExtraRoll = !!player.extraRoll && !STATE.game.finished;
    if (hasExtraRoll) {
      player.extraRoll = false;
      eventText += `\n\n🎲 ${player.name} 获得额外一次掷骰机会\n仍由 ${player.name} 行动`;
    }

    Renderer.showEvent(eventText);
    Renderer.addLog(eventText.replace(/\n/g, " / "));

    if (!hasExtraRoll) {
      STATE.game.turn++;
    }

    Renderer.renderBoard();
    Renderer.renderTurnInfo();
    Storage.autoSave();
  };

  const originalApplyTextEffectAndTrigger = Game.applyTextEffectAndTrigger;
  Game.applyTextEffectAndTrigger = async function patchedApplyTextEffectAndTrigger(player, text, depth) {
    const before = player.pos;
    const effectText = Game.tryApplyTextEffect(player, text);

    if (player.pos !== before) {
      const after = player.pos;
      STATE.game.animating = true;
      await Renderer.animateMove(player, before, after, { instantToStart: after === 0 });
      STATE.game.animating = false;

      let chainText = effectText ? `\n${effectText}` : "";
      chainText += await Game.resolveCurrentCell(player, depth + 1);
      return chainText;
    }

    return effectText ? `\n${effectText}` : "";
  };
})();
